payload.raw:
{
  "layout": "timeline",
  "title": "创新设计",
  "events": [
    {
      "date": "第1–2月",
      "title": "硬件攻坚阶段",
      "description": "完成仿水膜-鱼网结构液态金属复合材料制备，实现0.1mm级空间分辨率柔性传感器阵列微结构设计与信号标定，构建混合传感架构"
    },
    {
      "date": "第3月",
      "title": "算法开发阶段",
      "description": "研发分层CNN-LSTM手势识别模型，结合自适应滑动窗口分割与噪声抑制模块，实测识别准确率>98.2%，支持毫秒级实时推理"
    },
    {
      "date": "第4月",
      "title": "系统集成阶段",
      "description": "集成多模态交互协议栈，嵌入压力/温度动态反馈执行单元，构建感知-意图-反馈闭环，完成软硬件联调与触觉反馈模块部署"
    },
    {
      "date": "第5–6月",
      "title": "场景验证优化阶段",
      "description": "依托H-Box全息舱、李未可眼镜等平台，开展工业远程操控与虚拟实训多场景压力测试，完成用户体验迭代与标准接口固化"
    }
  ]
}

