payload.raw:
{
  "layout": "image-text",
  "title": "创新技术：基于智能数据手套的多模态人机交互系统",
  "subtitle": "构建“感知-意图-反馈”闭环，深度适配国产XR生态",
  "body": [
    {
      "type": "paragraph",
      "text": "系统通过融合肌电、弯曲度与IMU多源信号，构建动态意图推理引擎，实现交互意图精准解析与实时反馈，破解模态割裂与误判难题。自主设计轻量化通信协议，深度适配PICO、Unity中国版等国产XR平台，支持热插拔与跨平台加密传输，显著降低开发成本。全栈技术链贯通硬件感知、边缘计算与云端协同，形成安全可控、开放兼容的技术底座。核心成果发表于ICASSP（2023, 2024），获审稿人‘为多模态交互提供可复现范式’高度评价。"
    }
  ],
  "image": {
    "prompt": "Technical architecture diagram of a smart data glove system with multi-modal sensing, dynamic intent inference engine, and lightweight communication protocol, showing hardware sensors, edge computing layer, and cloud integration, rendered in clean vector style with labeled components",
    "alt": "技术框架图：包含多模态传感、动态意图推理引擎与轻量化通信协议的智能数据手套系统架构"
  }
}

